const webhookData = $('Webhook').first().json.body;
const message = (webhookData.message || '').trim();
const logId = $('Log Inquiry').first().json.id;
const threadTs = webhookData.thread_ts || '';

const thankPatterns = [
  /^(ありがとう|有難う|感謝|サンクス|thanks|thank you)/i,
  /^(了解|りょうかい|わかりました|承知|ok|オッケー)/i,
  /^(助かり|たすかり)/i
];

for (const p of thankPatterns) {
  if (p.test(message)) {
    return {
      json: {
        skipAgent: true,
        skipReason: 'thank_you',
        message: message,
        logId: logId,
        threadTs: threadTs,
        responseText: '👍 ご連絡ありがとうございます。他にご質問があればお気軽にどうぞ！'
      }
    };
  }
}

const infoPatterns = [
  /^[\d\-]{4,}$/,
  /^[\w\.\-]+@[\w\.\-]+\.[a-z]{2,}$/i,
  /^社員番号[はがを]?[:：\s]*[\d\-]+$/,
  /^(社員|従業員)?\s*(番号|No\.?|ナンバー)[はがを]?[:：\s]*[\d\-]+$/i,
  /^名前[はがを]?[:：\s]*.{1,20}$/,
  /^私[はが].{1,15}です$/,
  /^(メール|メアド|email)[はがを]?[:：\s]*[\w\.\-]+@[\w\.\-]+$/i,
  /^電話[はがを]?[:：\s]*[\d\-]+$/,
  /^ログインID[はがを]?[:：\s]*\S+$/i,
  /名前[はがをと].+[、,].*(ID|id|ユーザー|番号)/i,
  /(ID|id|ユーザー|番号)[はがをと]?.+[、,].*名前/i,
  /^.{2,10}[、,\s]+(ID|id)?[：:]?\s*[\d]{5,}$/
];

for (const p of infoPatterns) {
  if (p.test(message)) {
    return {
      json: {
        skipAgent: true,
        skipReason: 'info_only',
        message: message,
        logId: logId,
        threadTs: threadTs,
        responseText: '📝 情報を受け取りました。担当者に連絡し、確認後ご連絡いたします。'
      }
    };
  }
}

const cleanMsg = message.replace(/[\n\r]/g, ' ').trim();
if (cleanMsg.length <= 30 && /^[\d\w@\.\-]+$/.test(cleanMsg)) {
  return {
    json: {
      skipAgent: true,
      skipReason: 'short_data',
      message: message,
      logId: logId,
      threadTs: threadTs,
      responseText: '📝 情報を受け取りました。確認いたします。'
    }
  };
}

return {
  json: {
    skipAgent: false,
    message: message,
    logId: logId,
    threadTs: threadTs
  }
};

const webhookData = $('Webhook').first().json.body;
const historyRows = $('Fetch Conversation History').all();
const currentMessage = webhookData.message;

const messages = [];

function sanitizeText(text) {
  if (!text) return '';
  return String(text)
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"')
    .replace(/\n/g, '\\n')
    .replace(/\r/g, '\\r')
    .replace(/\t/g, '\\t');
}

for (const row of historyRows) {
  if (row.json.log_type === 'INQUIRY') {
    messages.push({
      role: 'user',
      content: [{ type: 'text', text: sanitizeText(row.json.message) }]
    });
  } else if (row.json.log_type === 'AI_RESPONSE' && row.json.ai_response_text) {
    messages.push({
      role: 'assistant',
      content: [{ type: 'text', text: sanitizeText(row.json.ai_response_text) }]
    });
  }
}

messages.push({
  role: 'user',
  content: [{ type: 'text', text: sanitizeText(currentMessage) }]
});

const payload = JSON.stringify({ messages });
const escapedPayload = payload.replace(/'/g, "''");

return {
  json: {
    messages,
    messageCount: messages.length,
    isMultiTurn: messages.length > 1,
    agentPayload: escapedPayload
  }
};

const response = $input.first().json;
const webhookData = $('Webhook').first().json.body;
const logId = $('Log Inquiry').first().json.id;
const messageInfo = $('Build Messages').first().json;

try {
  const agentResponse = JSON.parse(response.RESPONSE || response.response || '{}');

  const metadata = agentResponse.metadata || {};
  const tokensConsumed = metadata.usage?.tokens_consumed?.[0] || {};
  const tokensInput = tokensConsumed.input_tokens?.total || 0;
  const tokensOutput = tokensConsumed.output_tokens?.total || 0;
  const modelName = tokensConsumed.model_name || 'unknown';

  const contentArray = agentResponse.content || [];

  const toolResult = contentArray.find(c => c.type === 'tool_result');
  const searchResults = toolResult?.tool_result?.content?.[0]?.json?.search_results || [];
  const matchedKbIds = searchResults.map(r => r.id || r.kb_id).filter(Boolean).join(',');
  const confidenceScores = searchResults.map(r => ({
    id: r.id || r.kb_id,
    score: parseFloat(r['@CONFIDENCE_SCORE'] || r.columns?.['@CONFIDENCE_SCORE'] || '0'),
    text: (r.text || r.question || '').substring(0, 100)
  }));

  const textContent = contentArray.find(c => c.type === 'text');
  const content = textContent?.text || '';

  let parsed = {};
  let aiResponseText = '';

  const jsonMatch = content.match(/```json\s*([\s\S]*?)```/);
  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[1]);
    } catch (e) {
      const rawMatch = content.match(/\{[\s\S]*"escalation_team"[\s\S]*?\}/);
      if (rawMatch) parsed = JSON.parse(rawMatch[0]);
    }
    aiResponseText = content.split('```').pop()?.trim().replace(/^[-\s]+/, '') || '';
  } else {
    const rawMatch = content.match(/\{[\s\S]*"response"[\s\S]*?\}/);
    if (rawMatch) {
      try { parsed = JSON.parse(rawMatch[0]); } catch(e) {}
    }
    aiResponseText = content;
  }

  const summary = parsed.summary || '問い合わせ内容';
  const category = parsed.category || 'OTHER';
  const priority = parsed.priority || 'MEDIUM';
  const needsEscalation = parsed.needs_escalation === true || parsed.needsEscalation === true;
  const escalationTeam = parsed.escalation_team || parsed.escalationTeam || null;
  const resolutionSteps = JSON.stringify(parsed.resolution_steps || parsed.resolutionSteps || []);

  return {
    json: {
      inquiry_log_id: logId,
      user_id: webhookData.user_id,
      channel_id: webhookData.channel_id,
      thread_ts: webhookData.thread_ts || '',
      original_message: webhookData.message,
      category: category,
      priority: priority,
      summary: summary,
      ai_response_text: aiResponseText || content,
      raw_response: content,
      needs_escalation: needsEscalation,
      escalation_team: escalationTeam,
      resolution_steps: resolutionSteps,
      matched_kb_ids: matchedKbIds,
      confidence_scores: JSON.stringify(confidenceScores),
      tokens_input: tokensInput,
      tokens_output: tokensOutput,
      model_name: modelName,
      raw_agent_response: JSON.stringify(agentResponse),
      turn_number: messageInfo.messageCount,
      is_multi_turn: messageInfo.isMultiTurn
    }
  };
} catch (error) {
  return {
    json: {
      inquiry_log_id: logId,
      user_id: webhookData.user_id,
      channel_id: webhookData.channel_id,
      thread_ts: webhookData.thread_ts || '',
      original_message: webhookData.message,
      category: 'ERROR',
      priority: 'HIGH',
      summary: 'エラーが発生しました',
      ai_response_text: '申し訳ありません。処理中にエラーが発生しました。担当者に連絡いたします。',
      raw_response: '',
      needs_escalation: true,
      escalation_team: 'IT_SUPPORT',
      resolution_steps: '[]',
      matched_kb_ids: '',
      confidence_scores: '[]',
      tokens_input: 0,
      tokens_output: 0,
      model_name: 'unknown',
      raw_agent_response: JSON.stringify({ error: error.message }),
      turn_number: 1,
      is_multi_turn: false
    }
  };
}

